def remove_duplicates(arr):
    result = []
    for x in arr:
        if x not in result:
            result.append(x)

    return result


t = int(input())
for _ in range(t):
    n = int(input())
    arr = list(map(int, input().split()))

    ans = remove_duplicates(arr)
    print(len(ans))
    print(*ans)
